<div class="page-head"><div><h1><span class="mdi mdi-lock-clock icon-red"></span> Period Closing</h1><p class="muted">Lock prior accounting periods so transactions cannot be edited or deleted accidentally.</p></div></div>
<div class="card"><h2>Current Status</h2><?php if($lockedThrough): ?><p>Books are currently closed through <strong><?=h($lockedThrough)?></strong>.</p><?php else: ?><p>No closed period is currently active.</p><?php endif; ?></div>
<div class="card"><h2>Close a Period</h2><form method="post" action="<?=route('period_close')?>"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Lock transactions dated on or before<input type="date" name="locked_through" required></label><label>Note<input name="note" placeholder="Month-end close, year-end close, etc."></label><button><span class="mdi mdi-lock"></span> Close Period</button></form></div>
<h2>Close History</h2><table><tr><th>Locked Through</th><th>By</th><th>Note</th><th>Date</th><th>Action</th></tr><?php foreach($locks as $l):?><tr><td><?=h($l['locked_through'])?></td><td><?=h($l['user_name'] ?: $l['user_email'])?></td><td><?=h($l['note'])?></td><td><?=h($l['created_at'])?></td><td><form method="post" action="<?=route('period_unlock')?>" onsubmit="return confirm('Remove this period lock? Transactions in this period can be changed again.');"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="hidden" name="id" value="<?=h($l['id'])?>"><button class="danger small"><span class="mdi mdi-lock-open"></span> Re-open</button></form></td></tr><?php endforeach;?></table>
